int main() {
    int N;
    std::string line_buffer;

    while (true) {
        if (!std::getline(std::cin, line_buffer)) {
            N = 0; // Default to 0 if no valid input found (e.g., EOF reached)
            break;
        }
        std::istringstream iss(line_buffer);
        if (iss >> N && N >= 0) {
            break; // Valid input found
        }
    }

    for (int row = 1; row <= N; ++row) {
        for (int col = 1; col <= row; ++col) {
            std::cout << "*";
        }
        std::cout << '\n';
    }
    return 0;
}
